<?php
declare(strict_types=1);
namespace Vigilancia\Repositories;
use PDO;
final class NotificationRepository
{
 public function __construct(private PDO$pdo){}
 public function actor(int$id):?array{return$this->one("SELECT u.*,r.code role_code,r.name role_name,c.name company_name FROM users u JOIN roles r ON r.id=u.role_id JOIN surveillance_companies c ON c.id=u.surveillance_company_id WHERE u.id=? AND u.is_active=1",[$id]);}
 public function sync(array$a):void{$role=$a['role_code'];if(in_array($role,['superadmin','admin','supervisor'],true))$this->syncManagement($a);elseif($role==='guard')$this->syncGuard($a);elseif($role==='resident')$this->syncResident($a);}
 public function latest(int$user,int$limit=10):array{$limit=max(1,min(100,$limit));return$this->all("SELECT id,notification_type,title,message,priority,related_type,related_id,related_view,read_at,created_at FROM notifications WHERE user_id=? AND (expires_at IS NULL OR expires_at>UTC_TIMESTAMP()) ORDER BY created_at DESC,id DESC LIMIT $limit",[$user]);}
 public function unread(int$user):int{return(int)$this->value('SELECT COUNT(*) FROM notifications WHERE user_id=? AND read_at IS NULL AND (expires_at IS NULL OR expires_at>UTC_TIMESTAMP())',[$user]);}
 public function read(int$user,int$id):bool{$s=$this->pdo->prepare('UPDATE notifications SET read_at=COALESCE(read_at,UTC_TIMESTAMP()) WHERE id=? AND user_id=?');$s->execute([$id,$user]);return$s->rowCount()>0;}
 public function readAll(int$user):void{$this->pdo->prepare('UPDATE notifications SET read_at=COALESCE(read_at,UTC_TIMESTAMP()) WHERE user_id=? AND read_at IS NULL')->execute([$user]);}
 public function filters(array$a):array{$locations=$this->locations($a);$clients=[];foreach($locations as$l)$clients[(int)$l['client_id']]=['id'=>(int)$l['client_id'],'name'=>$l['client_name']];if($a['role_code']==='resident')$shifts=[];elseif($a['role_code']==='guard')$shifts=$this->all("SELECT DISTINCT s.id,s.name FROM guard_assignments ga JOIN shifts s ON s.id=ga.shift_id WHERE ga.guard_user_id=? AND ga.status='active' ORDER BY s.name",[$a['id']]);else$shifts=$this->all('SELECT id,name FROM shifts WHERE surveillance_company_id=? AND is_active=1 ORDER BY name',[$a['surveillance_company_id']]);return['clients'=>array_values($clients),'locations'=>$locations,'shifts'=>$shifts];}
 public function dashboard(array$a,array$f):array{$role=$a['role_code'];$date=preg_match('/^\d{4}-\d{2}-\d{2}$/',(string)($f['date']??''))?$f['date']:gmdate('Y-m-d');if($role==='resident')return$this->residentMetrics((int)$a['id'],$date);if($role==='guard')return$this->guardMetrics((int)$a['id'],$date);$locations=$this->locations($a);$ids=array_map('intval',array_column($locations,'id'));$location=(int)($f['location_id']??0);$client=(int)($f['client_id']??0);if($location)$ids=array_values(array_filter($ids,fn($id)=>$id===$location));elseif($client)$ids=array_values(array_filter($ids,function($id)use($locations,$client){foreach($locations as$l)if((int)$l['id']===$id)return(int)$l['client_id']===$client;return false;}));if(!$ids)return$this->emptyMetrics();$marks=implode(',',array_fill(0,count($ids),'?'));$shift=(int)($f['shift_id']??0);$shiftSql=$shift?' AND shift_id=?':'';$p=$shift?array_merge($ids,[$date,$shift]):array_merge($ids,[$date]);$active=(int)$this->value("SELECT COUNT(*) FROM operational_sessions WHERE location_id IN ($marks) AND status='active'",$ids);$late=(int)$this->value("SELECT COUNT(*) FROM attendance_records WHERE location_id IN ($marks) AND DATE(actual_entry_at)=? AND entry_classification='late'$shiftSql",$p);$absences=(int)$this->value("SELECT COUNT(*) FROM attendance_records WHERE location_id IN ($marks) AND DATE(scheduled_start_at)=? AND entry_classification='absence'$shiftSql",$p);$events=(int)$this->value("SELECT COUNT(*) FROM events WHERE location_id IN ($marks) AND DATE(occurred_at)=?",array_merge($ids,[$date]));$critical=(int)$this->value("SELECT COUNT(*) FROM events WHERE location_id IN ($marks) AND DATE(occurred_at)=? AND priority='critical'",array_merge($ids,[$date]));$visits=(int)$this->value("SELECT COUNT(*) FROM visitor_passes WHERE location_id IN ($marks) AND status='inside'",$ids);$pending=(int)$this->value("SELECT COUNT(*) FROM supervision_schedules WHERE location_id IN ($marks) AND status='pending' AND scheduled_at<=DATE_ADD(UTC_TIMESTAMP(),INTERVAL 30 DAY)",$ids);$rounds=(int)$this->value("SELECT COUNT(*) FROM rounds WHERE location_id IN ($marks) AND status='incomplete'",$ids);$hours=(float)$this->value("SELECT COALESCE(SUM(TIMESTAMPDIFF(MINUTE,actual_entry_at,COALESCE(actual_exit_at,UTC_TIMESTAMP())))/60,0) FROM attendance_records WHERE location_id IN ($marks) AND DATE(actual_entry_at)=?$shiftSql",$p);return['active_guards'=>$active,'present_guards'=>$active,'late'=>$late,'absences'=>$absences,'events'=>$events,'critical_events'=>$critical,'active_visits'=>$visits,'pending_supervisions'=>$pending,'incomplete_rounds'=>$rounds,'worked_hours'=>round($hours,1)];}
 private function syncManagement(array$a):void{$ids=array_map('intval',array_column($this->locations($a),'id'));if(!$ids)return;$m=implode(',',array_fill(0,count($ids),'?'));$rows=$this->all("SELECT os.id,os.location_id,os.started_at,os.ended_at,os.entry_classification,u.full_name,l.name location_name FROM operational_sessions os JOIN users u ON u.id=os.guard_user_id JOIN locations l ON l.id=os.location_id WHERE os.location_id IN ($m) AND os.started_at>=DATE_SUB(UTC_TIMESTAMP(),INTERVAL 30 DAY)",$ids);foreach($rows as$r){$this->add($a,'session_started','Inicio de sesión',"{$r['full_name']} inició sesión en {$r['location_name']}.",'normal','operational_session',$r['id'],'operacion',$r['location_id'],'start-'.$r['id'],$r['started_at']);if($r['ended_at'])$this->add($a,'session_closed','Cierre de sesión',"{$r['full_name']} cerró su sesión operativa.",'normal','operational_session',$r['id'],'operacion',$r['location_id'],'close-'.$r['id'],$r['ended_at']);if($r['entry_classification']==='late')$this->add($a,'attendance_late','Retardo registrado',"{$r['full_name']} registró una entrada con retardo.",'important','attendance',$r['id'],'asistencias',$r['location_id'],'late-'.$r['id'],$r['started_at']);if(!$r['ended_at']&&strtotime($r['started_at'].' UTC')<time()-16*3600)$this->add($a,'session_unclosed','Sesión sin cierre',"La sesión de {$r['full_name']} requiere revisión.",'important','operational_session',$r['id'],'operacion',$r['location_id'],'unclosed-'.$r['id'],$r['started_at']);}
 $absences=$this->all("SELECT ar.id,ar.location_id,ar.scheduled_start_at,u.full_name FROM attendance_records ar JOIN users u ON u.id=ar.guard_user_id WHERE ar.location_id IN ($m) AND ar.entry_classification='absence' AND ar.scheduled_start_at>=DATE_SUB(UTC_TIMESTAMP(),INTERVAL 30 DAY)",$ids);foreach($absences as$r)$this->add($a,'attendance_absence','Falta registrada',"{$r['full_name']} no registró entrada para su turno.",'important','attendance',$r['id'],'asistencias',$r['location_id'],'absence-'.$r['id'],$r['scheduled_start_at']);$events=$this->all("SELECT e.id,e.title,e.priority,e.location_id,e.occurred_at,l.name location_name FROM events e JOIN locations l ON l.id=e.location_id WHERE e.location_id IN ($m) AND e.occurred_at>=DATE_SUB(UTC_TIMESTAMP(),INTERVAL 30 DAY)",$ids);foreach($events as$r)$this->add($a,$r['priority']==='critical'?'event_critical':'event_created',$r['priority']==='critical'?'Evento crítico':'Evento registrado',"{$r['title']} · {$r['location_name']}",$r['priority'],'event',$r['id'],'eventos',$r['location_id'],'event-'.$r['id'],$r['occurred_at']);
 $rounds=$this->all("SELECT r.id,r.status,r.location_id,r.started_at,u.full_name FROM rounds r JOIN users u ON u.id=r.guard_user_id WHERE r.location_id IN ($m) AND r.started_at>=DATE_SUB(UTC_TIMESTAMP(),INTERVAL 30 DAY)",$ids);foreach($rounds as$r)$this->add($a,$r['status']==='incomplete'?'round_incomplete':'round_started',$r['status']==='incomplete'?'Recorrido incompleto':'Recorrido iniciado',"Recorrido de {$r['full_name']}.",$r['status']==='incomplete'?'important':'normal','round',$r['id'],'recorridos',$r['location_id'],'round-'.$r['id'].'-'.$r['status'],$r['started_at']);
 $sup=$this->all("SELECT ss.id,ss.location_id,ss.scheduled_at,l.name FROM supervision_schedules ss JOIN locations l ON l.id=ss.location_id WHERE ss.location_id IN ($m) AND ss.status='pending' AND ss.scheduled_at<=DATE_ADD(UTC_TIMESTAMP(),INTERVAL 30 DAY)",$ids);foreach($sup as$r)$this->add($a,'supervision_pending','Supervisión pendiente',"Supervisión programada en {$r['name']}.",'important','supervision_schedule',$r['id'],'supervisiones',$r['location_id'],'sup-pending-'.$r['id'],$r['scheduled_at']);$done=$this->all("SELECT id,folio,location_id,completed_at FROM supervisions WHERE location_id IN ($m) AND status='completed' AND completed_at>=DATE_SUB(UTC_TIMESTAMP(),INTERVAL 30 DAY)",$ids);foreach($done as$r)$this->add($a,'supervision_completed','Supervisión finalizada',"{$r['folio']} fue finalizada.",'normal','supervision',$r['id'],'supervisiones',$r['location_id'],'sup-done-'.$r['id'],$r['completed_at']);
 $visits=$this->all("SELECT vp.id,vp.visitor_name,vp.location_id,vp.created_at,va.entry_at,va.exit_at FROM visitor_passes vp LEFT JOIN visitor_accesses va ON va.visitor_pass_id=vp.id WHERE vp.location_id IN ($m) AND vp.created_at>=DATE_SUB(UTC_TIMESTAMP(),INTERVAL 30 DAY)",$ids);foreach($visits as$r){$this->add($a,'visit_created','Visita generada',"Acceso generado para {$r['visitor_name']}.",'normal','visit',$r['id'],'visitas',$r['location_id'],'visit-created-'.$r['id'],$r['created_at']);if($r['entry_at'])$this->add($a,'visit_entry','Entrada de visitante',"{$r['visitor_name']} ingresó a las instalaciones.",'normal','visit',$r['id'],'visitas',$r['location_id'],'visit-entry-'.$r['id'],$r['entry_at']);if($r['exit_at'])$this->add($a,'visit_exit','Salida de visitante',"{$r['visitor_name']} salió de las instalaciones.",'normal','visit',$r['id'],'visitas',$r['location_id'],'visit-exit-'.$r['id'],$r['exit_at']);}}
 private function syncGuard(array$a):void{$rows=$this->all("SELECT ec.id,ec.event_id,ec.comment,ec.created_at,e.location_id FROM event_comments ec JOIN events e ON e.id=ec.event_id WHERE e.guard_user_id=? AND ec.author_user_id<>? AND ec.created_at>=DATE_SUB(UTC_TIMESTAMP(),INTERVAL 30 DAY)",[$a['id'],$a['id']]);foreach($rows as$r)$this->add($a,'supervisor_comment','Comentario de supervisor',mb_strimwidth($r['comment'],0,180,'…'),'normal','event',$r['event_id'],'eventos',$r['location_id'],'event-comment-'.$r['id'],$r['created_at']);}
 private function syncResident(array$a):void{$rows=$this->all("SELECT vp.id,vp.visitor_name,vp.location_id,vp.created_at,va.entry_at,va.exit_at FROM visitor_passes vp LEFT JOIN visitor_accesses va ON va.visitor_pass_id=vp.id WHERE vp.resident_user_id=? AND vp.created_at>=DATE_SUB(UTC_TIMESTAMP(),INTERVAL 30 DAY)",[$a['id']]);foreach($rows as$r){$this->add($a,'visit_created','Visita generada',"Acceso generado para {$r['visitor_name']}.",'normal','visit',$r['id'],'visitas',$r['location_id'],'visit-created-'.$r['id'],$r['created_at']);if($r['entry_at'])$this->add($a,'visit_entry','Entrada de visitante',"{$r['visitor_name']} ingresó.",'normal','visit',$r['id'],'visitas',$r['location_id'],'visit-entry-'.$r['id'],$r['entry_at']);if($r['exit_at'])$this->add($a,'visit_exit','Salida de visitante',"{$r['visitor_name']} salió.",'normal','visit',$r['id'],'visitas',$r['location_id'],'visit-exit-'.$r['id'],$r['exit_at']);}}
 private function add(array$a,string$type,string$title,string$msg,string$priority,string$related,int$id,string$view,?int$location,string$key,string$date):void{$s=$this->pdo->prepare("INSERT IGNORE INTO notifications(user_id,notification_type,title,message,priority,related_type,related_id,related_view,location_id,deduplication_key,created_at,expires_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,DATE_ADD(?,INTERVAL 12 MONTH))");$s->execute([$a['id'],$type,$title,$msg,$priority,$related,$id,$view,$location,hash('sha256',$key),$date,$date]);}
 private function locations(array$a):array{if($a['role_code']==='resident')return$this->all("SELECT DISTINCT l.id,l.client_id,l.name location_name,c.name client_name FROM resident_units ru JOIN units u ON u.id=ru.unit_id JOIN locations l ON l.id=u.location_id JOIN clients c ON c.id=l.client_id WHERE ru.resident_user_id=? AND ru.is_active=1",[$a['id']]);if($a['role_code']==='guard')return$this->all("SELECT DISTINCT l.id,l.client_id,l.name location_name,c.name client_name FROM guard_assignments ga JOIN locations l ON l.id=ga.location_id JOIN clients c ON c.id=l.client_id WHERE ga.guard_user_id=? AND ga.status='active'",[$a['id']]);$sql="SELECT DISTINCT l.id,l.client_id,l.name location_name,c.name client_name FROM locations l JOIN clients c ON c.id=l.client_id";$p=[];if($a['role_code']==='supervisor'){$sql.=' JOIN user_location_scopes s ON s.location_id=l.id AND s.user_id=? AND s.is_active=1';$p[]=$a['id'];}elseif($a['role_code']==='admin'){$sql.=' LEFT JOIN user_location_scopes ls ON ls.location_id=l.id AND ls.user_id=? AND ls.is_active=1 LEFT JOIN user_client_scopes cs ON cs.client_id=c.id AND cs.user_id=? AND cs.is_active=1 WHERE c.surveillance_company_id=? AND (ls.user_id IS NOT NULL OR cs.user_id IS NOT NULL)';$p=[$a['id'],$a['id'],$a['surveillance_company_id']];}else{$sql.=' WHERE c.surveillance_company_id=?';$p[]=$a['surveillance_company_id'];}return$this->all($sql.' ORDER BY c.name,l.name',$p);}
 private function residentMetrics(int$user,string$date):array{return['active_visits'=>(int)$this->value("SELECT COUNT(*) FROM visitor_passes WHERE resident_user_id=? AND status='inside'",[$user]),'visits_today'=>(int)$this->value('SELECT COUNT(*) FROM visitor_passes WHERE resident_user_id=? AND DATE(scheduled_at)=?',[$user,$date]),'upcoming_visits'=>(int)$this->value("SELECT COUNT(*) FROM visitor_passes WHERE resident_user_id=? AND status='pending' AND scheduled_at>=UTC_TIMESTAMP()",[$user])];}
 private function guardMetrics(int$user,string$date):array{return['active_session'=>(int)$this->value("SELECT COUNT(*) FROM operational_sessions WHERE guard_user_id=? AND status='active'",[$user]),'events_today'=>(int)$this->value('SELECT COUNT(*) FROM events WHERE guard_user_id=? AND DATE(occurred_at)=?',[$user,$date]),'rounds_today'=>(int)$this->value('SELECT COUNT(*) FROM rounds WHERE guard_user_id=? AND DATE(started_at)=?',[$user,$date]),'worked_hours'=>round((float)$this->value('SELECT COALESCE(SUM(TIMESTAMPDIFF(MINUTE,actual_entry_at,COALESCE(actual_exit_at,UTC_TIMESTAMP())))/60,0) FROM attendance_records WHERE guard_user_id=? AND DATE(actual_entry_at)=?',[$user,$date]),1)];}
 private function emptyMetrics():array{return['active_guards'=>0,'present_guards'=>0,'late'=>0,'absences'=>0,'events'=>0,'critical_events'=>0,'active_visits'=>0,'pending_supervisions'=>0,'incomplete_rounds'=>0,'worked_hours'=>0];}
 private function one(string$q,array$p):?array{$s=$this->pdo->prepare($q);$s->execute($p);return$s->fetch()?:null;}private function all(string$q,array$p):array{$s=$this->pdo->prepare($q);$s->execute($p);return$s->fetchAll();}private function value(string$q,array$p):mixed{$s=$this->pdo->prepare($q);$s->execute($p);return$s->fetchColumn();}
}
